   cdk init app --language typescript
   ```

---

## 🛠️ Step-by-Step: Create a Secure S3 Bucket

### 1. **Install Required CDK Modules**

In your `cdk.json` or via `package.json`, ensure you have:

```bash
npm install @aws-cdk/aws-s3 @aws-cdk/aws-kms
```

---

### 2. **Create the S3 Bucket in CDK**

Here's a secure configuration for an S3 bucket to store **customer financial records**:

```typescript
// lib/s3-cdk-stack.ts

import * as cdk from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as kms from 'aws-cdk-lib/aws-kms';
import { Construct } from 'constructs';

export class S3CdkStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create a KMS key to encrypt the S3 bucket
    const encryptionKey = new kms.Key(this, 'CustomerFinancialDataKey', {
      description: 'KMS key for encrypting customer financial records',
      enableKeyRotation: true,
      alias: 'alias/customer-financial-data-key',
    });

    // Create the S3 bucket with encryption and access control
    const financialDataBucket = new s3.Bucket(this, 'CustomerFinancialDataBucket', {
      bucketName: 'customer-financial-records-bucket', // Customize as needed
      encryption: s3.BucketEncryption.KMS,
      encryptionKey: encryptionKey,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      versioned: true, // Enable versioning for data recovery
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Retain bucket on stack delete
      autoDeleteObjects: false, // Don't delete objects on removal
    });

    // Optional: Add logging (if needed)
    // financialDataBucket.addToResourcePolicy(...)

    // Optional: Add lifecycle rules for data retention
    financialDataBucket.addLifecycleRule({
      expiration: cdk.Duration.days(365), // Retain for 1 year
      transitions: [
        { storageClass: s3.StorageClass.INFREQUENT_ACCESS, transitionAfter: cdk.Duration.days(30) },
        { storageClass: s3.StorageClass.GLACIER, transitionAfter: cdk.Duration.days(90) },
      ],
    });

    // Optional: Add tags for compliance and cost tracking
    cdk.Tags.of(financialDataBucket).add('Purpose', 'CustomerFinancialData');
    cdk.Tags.of(financialDataBucket).add('Compliance', 'GDPR, CCPA');
  }
}
```

---

